import{_ as a,o as i,c as t,a2 as n}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"RFC-0014: Appliance Update System","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/rfcs/0014-appliance-update-system.md","filePath":"sovereign-os/rfcs/0014-appliance-update-system.md"}'),s={name:"sovereign-os/rfcs/0014-appliance-update-system.md"};function r(l,e,o,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="rfc-0014-appliance-update-system" tabindex="-1">RFC-0014: Appliance Update System <a class="header-anchor" href="#rfc-0014-appliance-update-system" aria-label="Permalink to &quot;RFC-0014: Appliance Update System&quot;">​</a></h1><p><strong>Status:</strong> Draft<br><strong>Author:</strong> Project creator and Codex<br><strong>Created:</strong> 2026-07-19<br><strong>Target:</strong> Milestone 01.1<br><strong>Related decision:</strong> <a href="./../adrs/0002-install-images-and-update-artifacts.html">ADR-0002</a></p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Introduce a signed, user-triggered update mechanism for installed Sovereign appliances. It updates pinned application containers and versioned appliance files while preserving <code>/data/sovereign</code>, validating health, and restoring the previous release after failure where data compatibility permits.</p><p>The concrete versioned file ownership, stable dispatch, and activation design is defined by the accepted <a href="./../design/versioned-appliance-release.html">Versioned Appliance Release Design</a>.</p><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>Publishing a new disk image does not provide a safe update path for an installed device. Rewriting the image erases the installation, while ad hoc <code>apt</code>, file-copy, or <code>docker pull latest</code> operations are neither reproducible nor safely reversible.</p><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Preserve Pi-hole configuration, credentials, and data.</li><li>Authenticate update metadata and payloads.</li><li>Reject incompatible hardware and versions.</li><li>Stage releases separately from the running version.</li><li>Back up before mutation.</li><li>Update a pinned Pi-hole container by digest.</li><li>Update appliance configuration as one versioned unit.</li><li>Gate commit on DNS and HTTP health checks.</li><li>Roll back automatically when safe.</li><li>Recover predictably after interruption.</li><li>Maintain local update history without mandatory telemetry.</li></ul><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h2><ul><li>A/B root filesystem implementation</li><li>Fleet orchestration</li><li>Silent unattended updates</li><li>Binary delta generation</li><li>Generic third-party plugin updates</li><li>Cross-distribution package management</li><li>Guaranteed rollback after irreversible migrations</li></ul><h2 id="release-model" tabindex="-1">Release Model <a class="header-anchor" href="#release-model" aria-label="Permalink to &quot;Release Model&quot;">​</a></h2><p>One source release may produce:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sovereign-os-&lt;version&gt;-rpi5-arm64.img.zst</span></span>
<span class="line"><span>                                        clean install and recovery</span></span>
<span class="line"><span>sovereign-update-&lt;version&gt;.tar.zst   installed device update</span></span>
<span class="line"><span>release-manifest.json                published release metadata</span></span>
<span class="line"><span>release-manifest.sig                 signature</span></span>
<span class="line"><span>SHA256SUMS                           transport integrity</span></span>
<span class="line"><span>release-notes.md                     human-readable changes</span></span></code></pre></div><p>Image and update artifacts must be produced from the same component-version manifest.</p><h2 id="component-version-model" tabindex="-1">Component Version Model <a class="header-anchor" href="#component-version-model" aria-label="Permalink to &quot;Component Version Model&quot;">​</a></h2><p>The device records:</p><ul><li>appliance version;</li><li>image/base version;</li><li>Pi-hole version and digest;</li><li>schema/migration version;</li><li>device compatibility identifier;</li><li>update channel;</li><li>active and previous release;</li><li>last update transaction state.</li></ul><h2 id="manifest-requirements" tabindex="-1">Manifest Requirements <a class="header-anchor" href="#manifest-requirements" aria-label="Permalink to &quot;Manifest Requirements&quot;">​</a></h2><p>The normative v1 contract is the JSON Schema at <a href="../../update/schema/sovereign-update-manifest-v1.schema.json"><code>update/schema/sovereign-update-manifest-v1.schema.json</code></a>, with a complete non-release fixture in <a href="../../update/examples/update-manifest-v1.example.json"><code>update/examples/update-manifest-v1.example.json</code></a>.</p><p>The signed manifest must include:</p><ul><li>release identifier and semantic/project version;</li><li>publication time;</li><li>channel;</li><li>compatible device identifiers;</li><li>minimum and maximum source versions where needed;</li><li>artifact URLs, sizes, and cryptographic digests;</li><li>component versions and OCI digests;</li><li>required free storage;</li><li>required reboot;</li><li>migration identifiers;</li><li>rollback limitations;</li><li>release notes reference;</li><li>signature/key identifier.</li></ul><p>Signatures establish publisher authenticity. Per-file cryptographic digests establish payload integrity.</p><h2 id="signature-format-and-key-management" tabindex="-1">Signature Format and Key Management <a class="header-anchor" href="#signature-format-and-key-management" aria-label="Permalink to &quot;Signature Format and Key Management&quot;">​</a></h2><p>Manifest v1 uses Ed25519. The publisher signs the exact UTF-8 bytes of <code>release-manifest.json</code>, including its final newline. There is no JSON reserialization or canonicalization during verification. The detached <code>release-manifest.sig</code> is the base64 encoding of the raw 64-byte signature.</p><p>The untrusted manifest&#39;s <code>signing.key_id</code> selects a public key from the device&#39;s preinstalled trust store. Selection does not confer trust. The client must reject an unknown, wrong-channel, expired, or revoked key before using any manifest URL or compatibility claim.</p><ul><li>The device image contains only trusted public verification keys.</li><li>Private release keys are stored outside source control and build images.</li><li>CI should request signing from a restricted mechanism rather than receive a long-lived unrestricted key where practical.</li><li>The format must support key rotation and revocation.</li><li>Development/test keys must not be trusted by production-channel devices.</li></ul><p>Production private-key custody and CI signing integration remain unresolved.</p><h2 id="persistent-and-replaceable-state" tabindex="-1">Persistent and Replaceable State <a class="header-anchor" href="#persistent-and-replaceable-state" aria-label="Permalink to &quot;Persistent and Replaceable State&quot;">​</a></h2><p>Persistent:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/data/sovereign/apps/</span></span>
<span class="line"><span>/data/sovereign/secrets/</span></span>
<span class="line"><span>/data/sovereign/configuration/</span></span>
<span class="line"><span>/data/sovereign/backups/</span></span>
<span class="line"><span>/data/sovereign/update-state/</span></span></code></pre></div><p>Replaceable/versioned:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/opt/sovereign/releases/&lt;version&gt;/</span></span>
<span class="line"><span>/opt/sovereign/current</span></span></code></pre></div><p>Host-generated runtime state such as Docker layers is replaceable unless a specific recovery requirement says otherwise.</p><h2 id="transaction-state-machine" tabindex="-1">Transaction State Machine <a class="header-anchor" href="#transaction-state-machine" aria-label="Permalink to &quot;Transaction State Machine&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>available</span></span>
<span class="line"><span>  -&gt; downloading</span></span>
<span class="line"><span>  -&gt; verified</span></span>
<span class="line"><span>  -&gt; backed_up</span></span>
<span class="line"><span>  -&gt; staged</span></span>
<span class="line"><span>  -&gt; activating</span></span>
<span class="line"><span>  -&gt; validating</span></span>
<span class="line"><span>     ├── committed</span></span>
<span class="line"><span>     └── rolling_back -&gt; rolled_back | recovery_required</span></span></code></pre></div><p>Transitions are recorded durably. An interrupted updater examines the journal and continues, rolls back, or stops with an actionable recovery state. It must never infer success solely because a process exited.</p><p>The normative snapshot schema is <a href="../../update/schema/transaction-state-v1.schema.json"><code>update/schema/transaction-state-v1.schema.json</code></a>. Each transition atomically replaces and fsyncs <code>state.json</code>, increments its sequence, and appends a non-secret event to <code>events.jsonl</code>. The complete durability and restart rules are defined in the <a href="./../../update/BACKUP_AND_JOURNAL.html">backup and journal contract</a>.</p><h2 id="installation-sequence" tabindex="-1">Installation Sequence <a class="header-anchor" href="#installation-sequence" aria-label="Permalink to &quot;Installation Sequence&quot;">​</a></h2><ol><li>Acquire a single update lock.</li><li>Refresh and verify signed release metadata.</li><li>Confirm channel, device, version, and migration compatibility.</li><li>Confirm disk space and system health.</li><li>Download payloads into a staging directory.</li><li>Verify all digests before privileged mutation.</li><li>Briefly quiesce Pi-hole, create and validate a pre-update backup, restart Pi-hole, and require DNS/HTTP health before continuing.</li><li>Install appliance files into a new version directory.</li><li>Import the pinned Pi-hole OCI image and verify its digest.</li><li>Validate Compose, Nginx, and systemd content offline.</li><li>Stop only affected services.</li><li>Apply reversible migrations.</li><li>Atomically switch the active-release reference.</li><li>Start services in dependency order.</li><li>Test TCP DNS, UDP DNS, <code>/dns/admin/</code>, and required API behavior.</li><li>Commit or roll back.</li><li>Retain bounded history and remove safe-to-delete staging data.</li></ol><h2 id="backup-and-migration" tabindex="-1">Backup and Migration <a class="header-anchor" href="#backup-and-migration" aria-label="Permalink to &quot;Backup and Migration&quot;">​</a></h2><p>Before activation, the updater backs up:</p><ul><li>Pi-hole persistent configuration and database required for restore;</li><li>Sovereign configuration;</li><li>update metadata;</li><li>previous appliance release reference.</li></ul><p>Backups must be validated enough to detect missing or unreadable content. Migration scripts declare whether they are reversible. If a migration is irreversible, the updater must clearly state that application rollback may require restoring the backup and must test that path before supporting the release.</p><p>The normative backup metadata schema is <a href="../../update/schema/backup-manifest-v1.schema.json"><code>update/schema/backup-manifest-v1.schema.json</code></a>. The initial consistency method stops Pi-hole while its authoritative state is archived, then restarts and health-checks it before the update proceeds. Four separate, mandatory payloads cover Pi-hole state, Sovereign configuration, secrets, and the previous release pointer. Runtime container storage, logs, staging data, and earlier backups are excluded.</p><p>Backup archives and manifests are root-only. Digests, sizes, role completeness, permissions, and safe archive listings must validate before <code>backed_up</code> can be recorded. Restore extracts into staging, validates again, preserves the old copy until health checks pass, and never deletes both the old and candidate trees on failure. See the <a href="./../../update/BACKUP_AND_JOURNAL.html">backup and journal contract</a>.</p><h2 id="health-and-commit" tabindex="-1">Health and Commit <a class="header-anchor" href="#health-and-commit" aria-label="Permalink to &quot;Health and Commit&quot;">​</a></h2><p>Minimum commit gates:</p><ul><li>Pi-hole container running;</li><li>TCP DNS query succeeds;</li><li>UDP DNS query succeeds;</li><li>upstream resolution succeeds when internet is available;</li><li>known blocked-domain behavior succeeds under controlled test data where practical;</li><li>Nginx configuration is valid;</li><li><code>/dns/admin/</code> returns the expected application response;</li><li><code>/dns/api/</code> authentication behavior is sane;</li><li><code>/admin/*</code> and <code>/api/*</code> remain outside Pi-hole;</li><li>persistent data is mounted from <code>/data</code>.</li></ul><p>Internet-independent checks must be separated from upstream-connectivity checks so an internet outage does not incorrectly classify a locally healthy update as corrupt.</p><h2 id="rollback" tabindex="-1">Rollback <a class="header-anchor" href="#rollback" aria-label="Permalink to &quot;Rollback&quot;">​</a></h2><p>Rollback restores:</p><ul><li>previous active-release reference;</li><li>previous Pi-hole container digest;</li><li>previous configuration;</li><li>persistent data from backup when the migration requires it.</li></ul><p>Rollback itself is health checked and journaled. If rollback fails, DNS recovery instructions must remain available locally.</p><h2 id="base-os-updates" tabindex="-1">Base-OS Updates <a class="header-anchor" href="#base-os-updates" aria-label="Permalink to &quot;Base-OS Updates&quot;">​</a></h2><p>This RFC does not make package-manager updates atomic. Base-OS security updates use a separately controlled procedure until an A/B system is selected.</p><p>The updater may report base-OS update status, but it must not represent an <code>apt</code> transaction as equivalent to a rollback-capable appliance update.</p><h2 id="distribution" tabindex="-1">Distribution <a class="header-anchor" href="#distribution" aria-label="Permalink to &quot;Distribution&quot;">​</a></h2><p>The update client fetches metadata and artifacts over HTTPS from a configurable release origin. Authenticity does not depend solely on TLS; signed metadata is mandatory.</p><p>No device account, telemetry, or inbound connection is required. Update checks are client-initiated.</p><h2 id="security-and-privacy" tabindex="-1">Security and Privacy <a class="header-anchor" href="#security-and-privacy" aria-label="Permalink to &quot;Security and Privacy&quot;">​</a></h2><ul><li>Verify signatures before trusting compatibility or URLs.</li><li>Verify digests before installation.</li><li>Treat archives and migration scripts as hostile until authenticated.</li><li>Prevent archive path traversal and unsafe ownership/modes.</li><li>Do not send device data beyond the minimum update request.</li><li>Do not expose Pi-hole data in update logs.</li><li>Restrict updater state and backups.</li><li>Protect against downgrade unless explicitly authorized for recovery.</li><li>Bound download, staging, backup, and log storage.</li></ul><h2 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to &quot;Testing Strategy&quot;">​</a></h2><ul><li>Signature, wrong-key, revoked-key, and tampered-manifest tests</li><li>Truncated and corrupted download tests</li><li>Compatibility and downgrade rejection</li><li>Insufficient-storage handling</li><li>Concurrent update lock</li><li>Power loss at every state transition</li><li>Invalid Compose/Nginx/systemd payloads</li><li>Container import and digest mismatch</li><li>Pi-hole migration and backup restore</li><li>DNS/UI health-check failure</li><li>Automatic rollback and rollback failure</li><li>Offline and upstream-DNS outage behavior</li><li>Update artifact and clean-image version consistency</li><li>Real Raspberry Pi update from every supported source version</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><h3 id="reflash-new-disk-images" tabindex="-1">Reflash new disk images <a class="header-anchor" href="#reflash-new-disk-images" aria-label="Permalink to &quot;Reflash new disk images&quot;">​</a></h3><p>Retained for recovery, rejected for routine updates because it erases installation state.</p><h3 id="docker-pull-and-compose-up" tabindex="-1">Docker pull and Compose up <a class="header-anchor" href="#docker-pull-and-compose-up" aria-label="Permalink to &quot;Docker pull and Compose up&quot;">​</a></h3><p>Useful primitives but insufficient alone: they do not authenticate the whole appliance release, back up data, coordinate configuration, journal migration, or provide product-level rollback.</p><h3 id="package-everything-as-debian-packages" tabindex="-1">Package everything as Debian packages <a class="header-anchor" href="#package-everything-as-debian-packages" aria-label="Permalink to &quot;Package everything as Debian packages&quot;">​</a></h3><p>Potentially useful for individual host components but does not solve container/data migration or atomic cross-component activation by itself.</p><h3 id="a-b-root-filesystems-now" tabindex="-1">A/B root filesystems now <a class="header-anchor" href="#a-b-root-filesystems-now" aria-label="Permalink to &quot;A/B root filesystems now&quot;">​</a></h3><p>Preferred long-term direction for base-OS updates but deferred until the application/appliance updater and target partition design are validated.</p><h2 id="unresolved-questions" tabindex="-1">Unresolved Questions <a class="header-anchor" href="#unresolved-questions" aria-label="Permalink to &quot;Unresolved Questions&quot;">​</a></h2><ul><li>Production signing-key custody, rotation publication, and CI integration</li><li>Release hosting</li><li>Backup format and validation depth</li><li>Pi-hole data compatibility matrix</li><li>Downgrade policy</li><li>Release retention and disk quotas</li><li>Whether to use an existing update framework for application bundles</li><li>Integration boundary with future A/B updater</li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><p>The v1 manifest schema, detached Ed25519 format, verifier trust ordering, backup contract, and transaction journal are now concrete. The RFC may become Proposed when the production key-custody workflow and rollback compatibility rules are concrete enough for independent security and failure-mode review.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>The high-level separation of images and updates is accepted in <a href="./../adrs/0002-install-images-and-update-artifacts.html">ADR-0002</a>. This detailed RFC remains Draft.</p>`,79)])])}const m=a(s,[["render",r]]);export{h as __pageData,m as default};
